#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

// lud_diagonal: Processes the diagonal BS×BS block at offset
// One thread per row of the block
kernel void lud_diagonal(global float* a, local float* temp, const int size, const int offset) {
    int i = get_global_id(0);
    if (i >= BLOCK_SIZE) return;

    int j, k;

    // Process row i of the diagonal block
    // Upper triangular part (j >= i)
    for (j = i; j < BLOCK_SIZE; j++) {
        float sum = 0.0f;
        for (k = 0; k < i; k++) {
            sum += a[(offset + i) * size + (offset + k)] * a[(offset + k) * size + (offset + j)];
        }
        a[(offset + i) * size + (offset + j)] -= sum;
    }

    // Lower triangular part (for rows below i)
    if (i < BLOCK_SIZE - 1) {
        float temp_val = 1.0f / a[(offset + i) * size + (offset + i)];
        for (j = i + 1; j < BLOCK_SIZE; j++) {
            float sum = 0.0f;
            for (k = 0; k < i; k++) {
                sum += a[(offset + j) * size + (offset + k)] * a[(offset + k) * size + (offset + i)];
            }
            a[(offset + j) * size + (offset + i)] = (a[(offset + j) * size + (offset + i)] - sum) * temp_val;
        }
    }
}

// lud_perimeter: Processes perimeter blocks (right and bottom of diagonal)
// Thread index determines which block and which side (right or bottom)
kernel void lud_perimeter(global float* a, local float* temp_top, local float* temp_left, local float* temp_diag, const int size, const int offset) {
    int idx = get_global_id(0);
    int num_blocks = (size - offset - BLOCK_SIZE) / BLOCK_SIZE;

    if (idx >= num_blocks * 2 * BLOCK_SIZE) return;

    int block_idx = idx / (BLOCK_SIZE * 2);
    int side_idx = (idx / BLOCK_SIZE) % 2;
    int thread_idx = idx % BLOCK_SIZE;

    int i, j, k;

    // Load diagonal block into local memory (all threads cooperate)
    if (thread_idx < BLOCK_SIZE) {
        for (i = 0; i < BLOCK_SIZE; i++) {
            temp_diag[thread_idx * BLOCK_SIZE + i] = a[(offset + thread_idx) * size + (offset + i)];
        }
    }

    if (side_idx == 0) {
        // Right perimeter (columns to the right of diagonal block)
        int j_global = offset + BLOCK_SIZE + block_idx * BLOCK_SIZE;

        for (j = 0; j < BLOCK_SIZE; j++) {
            for (i = 0; i < BLOCK_SIZE; i++) {
                float sum = 0.0f;
                for (k = 0; k < i; k++) {
                    sum += temp_diag[i * BLOCK_SIZE + k] * a[(offset + k) * size + (j_global + j)];
                }
                a[(offset + i) * size + (j_global + j)] -= sum;
            }
        }
    } else {
        // Bottom perimeter (rows below diagonal block)
        int i_global = offset + BLOCK_SIZE + block_idx * BLOCK_SIZE;

        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                float sum = 0.0f;
                for (k = 0; k < j; k++) {
                    sum += a[(i_global + i) * size + (offset + k)] * temp_diag[k * BLOCK_SIZE + j];
                }
                float diag_val = a[(offset + j) * size + (offset + j)];
                a[(i_global + i) * size + (offset + j)] = (a[(i_global + i) * size + (offset + j)] - sum) / diag_val;
            }
        }
    }
}

// lud_internal: Processes internal blocks (not on diagonal or perimeter)
// 2D grid of threads, each handles one BS×BS block
kernel void lud_internal(global float* a, local float* temp_top, local float* temp_left, const int size, const int offset) {
    int idx = get_global_id(0);
    int idy = get_global_id(1);
    int num_blocks = (size - offset - BLOCK_SIZE) / BLOCK_SIZE;

    if (idx >= num_blocks || idy >= num_blocks) return;

    int i_global = offset + BLOCK_SIZE + idx * BLOCK_SIZE;
    int j_global = offset + BLOCK_SIZE + idy * BLOCK_SIZE;

    int i, j, k;

    // Load top block (from diagonal row) into local memory
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            temp_top[i * BLOCK_SIZE + j] = a[(offset + i) * size + (j_global + j)];
        }
    }

    // Load left block (from diagonal column) into local memory
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            temp_left[i * BLOCK_SIZE + j] = a[(i_global + i) * size + (offset + j)];
        }
    }

    // Update internal block
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            float sum = 0.0f;
            for (k = 0; k < BLOCK_SIZE; k++) {
                sum += temp_left[i * BLOCK_SIZE + k] * temp_top[k * BLOCK_SIZE + j];
            }
            a[(i_global + i) * size + (j_global + j)] -= sum;
        }
    }
}
